function BudgetCard({ budget }) {

  if (!budget) return null;

  return (

    <div className="card">

      <h2>Budget Details</h2>

      <p>
        Hotel Cost:
        ₹{budget.hotel_cost}
      </p>

      <p>
        Food Cost:
        ₹{budget.food_cost}
      </p>

      <p>
        Transport Cost:
        ₹{budget.transport_cost}
      </p>

      <h3>
        Total Cost:
        ₹{budget.total_cost}
      </h3>

    </div>
  );
}

export default BudgetCard;
